-- Phase 2 auth/profile schema additions. Run with Prisma migrate in environments with DATABASE_URL.
ALTER TABLE "Session" ADD COLUMN IF NOT EXISTS "refreshTokenHash" TEXT, ADD COLUMN IF NOT EXISTS "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE "RefreshToken" ADD COLUMN IF NOT EXISTS "sessionId" TEXT, ADD COLUMN IF NOT EXISTS "replacedByTokenId" TEXT;
CREATE TABLE IF NOT EXISTS "EmailVerificationToken" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL, "tokenHash" TEXT NOT NULL UNIQUE, "expiresAt" TIMESTAMP(3) NOT NULL, "consumedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "PasswordResetToken" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL, "tokenHash" TEXT NOT NULL UNIQUE, "expiresAt" TIMESTAMP(3) NOT NULL, "consumedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "NotificationSetting" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL UNIQUE, "email" BOOLEAN NOT NULL DEFAULT true, "sms" BOOLEAN NOT NULL DEFAULT false, "push" BOOLEAN NOT NULL DEFAULT true, "marketing" BOOLEAN NOT NULL DEFAULT false, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "NotificationSetting_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "SavedPaymentMethod" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL, "provider" TEXT NOT NULL, "providerMethodId" TEXT NOT NULL, "brand" TEXT, "last4" TEXT NOT NULL, "expMonth" INTEGER NOT NULL, "expYear" INTEGER NOT NULL, "isDefault" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "SavedPaymentMethod_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE);
